package org.eclipse.rdf4j.query.algebra.evaluation.optimizer;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertSame;

import org.eclipse.rdf4j.query.algebra.SingletonSet;
import org.eclipse.rdf4j.query.algebra.evaluation.impl.EvaluationStatistics;
import org.junit.jupiter.api.Test;

class OptimizationContextTest {

	@Test
	void fromBuildsDefaultEstimatorAndStatsProvider() {
		EvaluationStatistics evaluationStatistics = new EvaluationStatistics();
		JoinStatsProvider joinStatsProvider = new MemoryJoinStats();

		OptimizationContext context = OptimizationContext.from(evaluationStatistics, joinStatsProvider);

		assertSame(evaluationStatistics, context.getEvaluationStatistics());
		assertSame(joinStatsProvider, context.getJoinStatsProvider());

		CardinalityEstimate estimate = context.getCardinalityEstimator().estimate(new SingletonSet());
		assertEquals(1.0d, estimate.getEstimate());
		assertEquals(1.0d, estimate.getLowerBound());
		assertEquals(1.0d, estimate.getUpperBound());
		assertFalse(estimate.getSources().isEmpty());
	}
}
